import{_ as t,c as o,o as r,ag as a}from"./chunks/framework.CSeR4K32.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/en/guide/docker/docker_precheck.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"OneClickVirt"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Introduction"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/en/guide/docker/docker_precheck.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Introduction"}]]},"headers":[],"relativePath":"en/guide/docker/docker_precheck.md","filePath":"en/guide/docker/docker_precheck.md","lastUpdated":1781276860000}'),n={name:"en/guide/docker/docker_precheck.md"};function i(s,e,c,d,l,h){return r(),o("div",null,e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>This page introduces the standard (non-customized) workflow.</p><p>If your host has no IPv6 subnet but you want to assign IPv6 addresses to containers, check the <code>Customize</code> section in the <code>Docker</code> module for <code>Attach a free IPv6 address segment to the host</code>, then attach an IPv6 subnet before installation.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If the host has IPv6 networking, installation may change host network structure. Ensure the host can be recovered/reinstalled at any time, and do not run on machines with critical data.</p></div><p>Feel free to give the project a <code>Star</code> for free support!--&gt;<a href="https://github.com/oneclickvirt/docker" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/docker</a></p><h2 id="project-features" tabindex="-1">Project Features <a class="header-anchor" href="#project-features" aria-label="Permalink to &quot;Project Features&quot;">​</a></h2><p>Bulk or individual NAT server provisioning via Docker.</p><p>Uses Debian by default (Alpine optional). Each container includes 1 external SSH port plus 25 matched internal/external ports, with optional IPv6 binding.</p><p>Containers are created as unprivileged by default, and Docker daemon sockets are not mounted from the host. Therefore, <strong>Docker-in-Docker nested virtualization is not supported inside these NAT containers</strong>.</p><p>By default, lxcfs is installed and enabled, so that when querying resources within a container, CPU and memory use the configured view instead of the host&#39;s view.</p><p>By default, the installer lets you choose whether to share host disk space and whether to enable container disk-size limits.</p><h2 id="configuration-requirements" tabindex="-1">Configuration requirements <a class="header-anchor" href="#configuration-requirements" aria-label="Permalink to &quot;Configuration requirements&quot;">​</a></h2><p>Any system that can install Docker can use this solution. The host should be able to access GitHub raw content, and at least 3 GB of free disk space is recommended.</p><p>(If you need IPv6 binding, install Docker through this project&#39;s installer so the required network presets are applied automatically.)</p><p>If your hardware is moderate and you need stricter resource controls (especially disk limits), use the Incus module to create LXC containers in batch.</p><p>If your hardware has strong capacity and you need larger-scale VM workloads, use the PVE module to create KVM VMs in batch.</p>',16)]))}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
